'use client';

import { createBrowserSupabaseClient } from './client';
import { Database } from '@/types/supabase';
import { RealtimeChannel, RealtimePostgresChangesPayload } from '@supabase/supabase-js';

// нҲ¬н‘ң кҙҖл Ё н…Ңмқҙлё” нғҖмһ… м •мқҳ
type VoteTable = Database['public']['Tables']['vote']['Row'];
type VoteItemTable = Database['public']['Tables']['vote_item']['Row'];
type VotePickTable = Database['public']['Tables']['vote_pick']['Row'];
type ArtistVoteTable = Database['public']['Tables']['artist_vote']['Row'];
type ArtistVoteItemTable = Database['public']['Tables']['artist_vote_item']['Row'];

// Realtime мқҙлІӨнҠё нғҖмһ… м •мқҳ
export type VoteRealtimeEvent = 
  | { type: 'vote_updated'; payload: VoteTable }
  | { type: 'vote_item_updated'; payload: VoteItemTable }
  | { type: 'vote_pick_created'; payload: VotePickTable }
  | { type: 'artist_vote_updated'; payload: ArtistVoteTable }
  | { type: 'artist_vote_item_updated'; payload: ArtistVoteItemTable };

// м—°кІ° мғҒнғң нғҖмһ… (нҷ•мһҘлҗЁ)
export type ConnectionStatus = 
  | 'connecting' 
  | 'connected' 
  | 'disconnected' 
  | 'error' 
  | 'network_error'
  | 'reconnecting'
  | 'suspended';

// мҳӨлҘҳ нғҖмһ… м •мқҳ
export type ErrorType = 
  | 'network'
  | 'subscription'
  | 'authentication'
  | 'timeout'
  | 'rate_limit'
  | 'unknown';

// м—°кІ° м •ліҙ нғҖмһ…
export interface ConnectionInfo {
  status: ConnectionStatus;
  lastConnected?: Date;
  lastError?: {
    type: ErrorType;
    message: string;
    timestamp: Date;
    attemptCount: number;
  };
  reconnectAttempts: number;
  maxReconnectAttempts: number;
  nextReconnectAt?: Date;
  isOnline: boolean;
  isVisible: boolean;
}

// мқҙлІӨнҠё лҰ¬мҠӨл„Ҳ нғҖмһ…
export type VoteEventListener = (event: VoteRealtimeEvent) => void;
export type ConnectionStatusListener = (status: ConnectionStatus, info: ConnectionInfo) => void;

// лҚ°мқҙн„° лҸҷкё°нҷ” мҪңл°ұ нғҖмһ…
export type DataSyncCallback = (voteId: number) => Promise<void>;

/**
 * нҲ¬н‘ң мӢңмҠӨн…ңмқ„ мң„н•ң кі кёү Realtime м„ңл№„мҠӨ нҒҙлһҳмҠӨ
 */
export class VoteRealtimeService {
  private supabase = createBrowserSupabaseClient();
  private channels: Map<string, RealtimeChannel> = new Map();
  private eventListeners: Set<VoteEventListener> = new Set();
  private statusListeners: Set<ConnectionStatusListener> = new Set();
  private dataSyncCallbacks: Map<number, DataSyncCallback> = new Map();
  
  // м—°кІ° мғҒнғң кҙҖлҰ¬
  private connectionStatus: ConnectionStatus = 'disconnected';
  private connectionInfo: ConnectionInfo = {
    status: 'disconnected',
    reconnectAttempts: 0,
    maxReconnectAttempts: 10, // мҰқк°Җлҗң мһ¬мӢңлҸ„ нҡҹмҲҳ
    isOnline: true, // м„ңлІ„мӮ¬мқҙл“ңм—җм„ңлҠ” кё°ліёк°’мңјлЎң м„Өм •
    isVisible: true // м„ңлІ„мӮ¬мқҙл“ңм—җм„ңлҠ” кё°ліёк°’мңјлЎң м„Өм •
  };
  
  // мһ¬м—°кІ° м„Өм •
  private reconnectAttempts = 0;
  private maxReconnectAttempts = 10;
  private baseReconnectDelay = 1000; // 1мҙҲ
  private maxReconnectDelay = 60000; // 60мҙҲ
  private reconnectTimeouts: Map<string, NodeJS.Timeout> = new Map();
  
  // л„ӨнҠёмӣҢнҒ¬ л°Ҹ к°ҖмӢңм„ұ мғҒнғң
  private isOnline = true; // м„ңлІ„мӮ¬мқҙл“ңм—җм„ңлҠ” кё°ліёк°’мңјлЎң м„Өм •
  private isVisible = true; // м„ңлІ„мӮ¬мқҙл“ңм—җм„ңлҠ” кё°ліёк°’мңјлЎң м„Өм •
  private heartbeatInterval: NodeJS.Timeout | null = null;
  private lastHeartbeat: Date | null = null;
  
  // мқҙлІӨнҠё нҒҗ (мҳӨн”„лқјмқё мӢң мқҙлІӨнҠё м ҖмһҘ)
  private pendingEvents: VoteRealtimeEvent[] = [];
  private maxPendingEvents = 100;

  constructor() {
    // лёҢлқјмҡ°м Җ нҷҳкІҪм—җм„ңл§Ң мҙҲкё°нҷ”
    if (typeof window !== 'undefined') {
      // лёҢлқјмҡ°м Җ нҷҳкІҪм—җм„ң мӢӨм ң к°’мңјлЎң м„Өм •
      this.isOnline = navigator.onLine;
      this.isVisible = !document.hidden;
      this.connectionInfo.isOnline = this.isOnline;
      this.connectionInfo.isVisible = this.isVisible;
      
      this.setupNetworkListeners();
      this.setupVisibilityListeners();
      this.startHeartbeat();
    }
  }

  /**
   * л„ӨнҠёмӣҢнҒ¬ мғҒнғң к°җм§Җ м„Өм •
   */
  private setupNetworkListeners(): void {
    if (typeof window !== 'undefined') {
      window.addEventListener('online', this.handleOnline.bind(this));
      window.addEventListener('offline', this.handleOffline.bind(this));
    }
  }

  /**
   * нҺҳмқҙм§Җ к°ҖмӢңм„ұ к°җм§Җ м„Өм •
   */
  private setupVisibilityListeners(): void {
    if (typeof document !== 'undefined') {
      document.addEventListener('visibilitychange', this.handleVisibilityChange.bind(this));
    }
  }

  /**
   * н•ҳнҠёл№„нҠё мӢңмһ‘ (м—°кІ° мғҒнғң нҷ•мқё)
   */
  private startHeartbeat(): void {
    this.heartbeatInterval = setInterval(() => {
      this.lastHeartbeat = new Date();
      
      // м—°кІ°лҗҳм–ҙ мһҲм§Җл§Ң мқјм • мӢңк°„ мқҙмғҒ мқҙлІӨнҠёк°Җ м—Ҷмңјл©ҙ м—°кІ° нҷ•мқё
      if (this.connectionStatus === 'connected') {
        const timeSinceLastHeartbeat = Date.now() - (this.lastHeartbeat?.getTime() || 0);
        if (timeSinceLastHeartbeat > 30000) { // 30мҙҲ
          this.checkConnection();
        }
      }
    }, 10000); // 10мҙҲл§ҲлӢӨ нҷ•мқё
  }

  /**
   * мҳЁлқјмқё мғҒнғң мІҳлҰ¬
   */
  private handleOnline(): void {
    this.isOnline = true;
    this.connectionInfo.isOnline = true;
    
    if (process.env.NODE_ENV === 'development') {
      console.log('[VoteRealtime] л„ӨнҠёмӣҢнҒ¬ мҳЁлқјмқё ліөкө¬');
    }
    
    // л„ӨнҠёмӣҢнҒ¬ ліөкө¬ мӢң мһҗлҸҷ мһ¬м—°кІ°
    this.reconnectAllChannels();
  }

  /**
   * мҳӨн”„лқјмқё мғҒнғң мІҳлҰ¬
   */
  private handleOffline(): void {
    this.isOnline = false;
    this.connectionInfo.isOnline = false;
    this.updateConnectionStatus('network_error');
    
    if (process.env.NODE_ENV === 'development') {
      console.log('[VoteRealtime] л„ӨнҠёмӣҢнҒ¬ мҳӨн”„лқјмқё');
    }
  }

  /**
   * нҺҳмқҙм§Җ к°ҖмӢңм„ұ ліҖкІҪ мІҳлҰ¬
   */
  private handleVisibilityChange(): void {
    if (typeof document !== 'undefined') {
      this.isVisible = !document.hidden;
      this.connectionInfo.isVisible = this.isVisible;
      
      if (this.isVisible) {
        // нҺҳмқҙм§Җк°Җ ліҙмқҙкІҢ лҗҳл©ҙ м—°кІ° мғҒнғң нҷ•мқё л°Ҹ мһ¬м—°кІ°
        if (process.env.NODE_ENV === 'development') {
          console.log('[VoteRealtime] нҺҳмқҙм§Җ нҷңм„ұнҷ” - м—°кІ° нҷ•мқё');
        }
        this.checkConnection();
      } else {
        // нҺҳмқҙм§Җк°Җ мҲЁкІЁм§Җл©ҙ м—°кІ° мқјмӢң мӨ‘лӢЁ (л°°н„°лҰ¬ м Ҳм•Ҫ)
        if (process.env.NODE_ENV === 'development') {
          console.log('[VoteRealtime] нҺҳмқҙм§Җ л№„нҷңм„ұнҷ” - м—°кІ° мқјмӢң мӨ‘лӢЁ');
        }
        this.updateConnectionStatus('suspended');
      }
    }
  }

  /**
   * м—°кІ° мғҒнғң нҷ•мқё
   */
  private checkConnection(): void {
    // мҳЁлқјмқёмқҙкі  нҺҳмқҙм§Җк°Җ ліҙмқҙлҠ” мғҒнғңм—җм„ңл§Ң м—°кІ° нҷ•мқё
    if (!this.isOnline || !this.isVisible) {
      return;
    }

    // м—°кІ°лҗҳм–ҙ мһҲм§Җ м•Ҡмңјл©ҙ мһ¬м—°кІ° мӢңлҸ„
    if (this.connectionStatus !== 'connected') {
      this.reconnectAllChannels();
    }
  }

  /**
   * лӘЁл“  мұ„л„җ мһ¬м—°кІ°
   */
  private reconnectAllChannels(): void {
    if (!this.isOnline || !this.isVisible) {
      return;
    }

    const channelNames = Array.from(this.channels.keys());
    
    // кё°мЎҙ мұ„л„җл“Ө м •лҰ¬
    this.channels.forEach((channel, channelName) => {
      this.supabase.removeChannel(channel);
    });
    this.channels.clear();

    // мһ¬м—°кІ° мӢңлҸ„
    channelNames.forEach(channelName => {
      const voteId = this.extractVoteIdFromChannelName(channelName);
      if (voteId) {
        if (channelName.startsWith('artist_vote_')) {
          this.subscribeToArtistVote(voteId);
        } else {
          this.subscribeToVote(voteId);
        }
      }
    });
  }

  /**
   * мұ„л„җлӘ…м—җм„ң нҲ¬н‘ң ID м¶”м¶ң
   */
  private extractVoteIdFromChannelName(channelName: string): number | null {
    const match = channelName.match(/(?:artist_)?vote_(\d+)/);
    return match ? parseInt(match[1], 10) : null;
  }

  /**
   * нҲ¬н‘ң мқҙлІӨнҠё лҰ¬мҠӨл„Ҳ м¶”к°Җ
   */
  addEventListener(listener: VoteEventListener): void {
    this.eventListeners.add(listener);
  }

  /**
   * нҲ¬н‘ң мқҙлІӨнҠё лҰ¬мҠӨл„Ҳ м ңкұ°
   */
  removeEventListener(listener: VoteEventListener): void {
    this.eventListeners.delete(listener);
  }

  /**
   * м—°кІ° мғҒнғң лҰ¬мҠӨл„Ҳ м¶”к°Җ
   */
  addStatusListener(listener: ConnectionStatusListener): void {
    this.statusListeners.add(listener);
  }

  /**
   * м—°кІ° мғҒнғң лҰ¬мҠӨл„Ҳ м ңкұ°
   */
  removeStatusListener(listener: ConnectionStatusListener): void {
    this.statusListeners.delete(listener);
  }

  /**
   * лҚ°мқҙн„° лҸҷкё°нҷ” мҪңл°ұ м¶”к°Җ
   */
  addDataSyncCallback(voteId: number, callback: DataSyncCallback): void {
    this.dataSyncCallbacks.set(voteId, callback);
  }

  /**
   * лҚ°мқҙн„° лҸҷкё°нҷ” мҪңл°ұ м ңкұ°
   */
  removeDataSyncCallback(voteId: number): void {
    this.dataSyncCallbacks.delete(voteId);
  }

  /**
   * нҳ„мһ¬ м—°кІ° мғҒнғң л°ҳнҷҳ
   */
  getConnectionStatus(): ConnectionStatus {
    return this.connectionStatus;
  }

  /**
   * м—°кІ° м •ліҙ л°ҳнҷҳ
   */
  getConnectionInfo(): ConnectionInfo {
    return { ...this.connectionInfo };
  }

  /**
   * м—°кІ° мғҒнғң м—…лҚ°мқҙнҠё л°Ҹ лҰ¬мҠӨл„Ҳ м•ҢлҰј
   */
  private updateConnectionStatus(status: ConnectionStatus, error?: { type: ErrorType; message: string }): void {
    const previousStatus = this.connectionStatus;
    this.connectionStatus = status;
    
    // м—°кІ° м •ліҙ м—…лҚ°мқҙнҠё
    this.connectionInfo.status = status;
    this.connectionInfo.reconnectAttempts = this.reconnectAttempts;
    
    if (status === 'connected') {
      this.connectionInfo.lastConnected = new Date();
      this.connectionInfo.lastError = undefined;
    } else if (error) {
      this.connectionInfo.lastError = {
        ...error,
        timestamp: new Date(),
        attemptCount: this.reconnectAttempts
      };
    }
    
    // мғҒнғңк°Җ ліҖкІҪлҗң кІҪмҡ°м—җл§Ң лҰ¬мҠӨл„Ҳ м•ҢлҰј
    if (previousStatus !== status) {
      this.statusListeners.forEach(listener => {
        try {
          listener(status, this.connectionInfo);
        } catch (err) {
          console.error('[VoteRealtime] мғҒнғң лҰ¬мҠӨл„Ҳ мҳӨлҘҳ:', err);
        }
      });
      
      if (process.env.NODE_ENV === 'development') {
        console.log(`[VoteRealtime] м—°кІ° мғҒнғң ліҖкІҪ: ${previousStatus} вҶ’ ${status}`);
      }
    }
    
    // м—°кІ° м„ұкіө мӢң лҚ°мқҙн„° лҸҷкё°нҷ” мӢӨн–ү
    if (status === 'connected' && previousStatus !== 'connected') {
      this.performDataSync();
    }
  }

  /**
   * лҚ°мқҙн„° лҸҷкё°нҷ” мӢӨн–ү
   */
  private async performDataSync(): Promise<void> {
    if (this.dataSyncCallbacks.size === 0) return;
    
    // Mapмқ„ ArrayлЎң ліҖнҷҳн•ҳм—¬ мқҙн„°л Ҳмқҙм…ҳ
    const entries = Array.from(this.dataSyncCallbacks.entries());
    for (const [voteId, callback] of entries) {
      try {
        await callback(voteId);
        if (process.env.NODE_ENV === 'development') {
          console.log(`[VoteRealtime] нҲ¬н‘ң ${voteId} лҚ°мқҙн„° лҸҷкё°нҷ” мҷ„лЈҢ`);
        }
      } catch (error) {
        console.error(`[VoteRealtime] нҲ¬н‘ң ${voteId} лҚ°мқҙн„° лҸҷкё°нҷ” мӢӨнҢЁ:`, error);
      }
    }
  }

  /**
   * мқҙлІӨнҠёлҘј лӘЁл“  лҰ¬мҠӨл„Ҳм—җкІҢ м „нҢҢ
   */
  private emitEvent(event: VoteRealtimeEvent): void {
    // мҳӨн”„лқјмқё мғҒнғңл©ҙ мқҙлІӨнҠёлҘј нҒҗм—җ м ҖмһҘ
    if (!this.isOnline || this.connectionStatus !== 'connected') {
      this.queueEvent(event);
      return;
    }
    
    this.eventListeners.forEach(listener => {
      try {
        listener(event);
      } catch (error) {
        console.error('[VoteRealtime] мқҙлІӨнҠё лҰ¬мҠӨл„Ҳ мҳӨлҘҳ:', error);
      }
    });
  }

  /**
   * мқҙлІӨнҠёлҘј нҒҗм—җ м ҖмһҘ
   */
  private queueEvent(event: VoteRealtimeEvent): void {
    if (this.pendingEvents.length >= this.maxPendingEvents) {
      // нҒҗк°Җ к°Җл“қ м°јмңјл©ҙ мҳӨлһҳлҗң мқҙлІӨнҠё м ңкұ°
      this.pendingEvents.shift();
    }
    
    this.pendingEvents.push(event);
    
    if (process.env.NODE_ENV === 'development') {
      console.log(`[VoteRealtime] мқҙлІӨнҠё нҒҗм—җ м ҖмһҘ: ${event.type} (нҒҗ нҒ¬кё°: ${this.pendingEvents.length})`);
    }
  }

  /**
   * нҒҗм—җ м ҖмһҘлҗң мқҙлІӨнҠёл“Өмқ„ мІҳлҰ¬
   */
  private processPendingEvents(): void {
    if (this.pendingEvents.length === 0) return;
    
    const events = [...this.pendingEvents];
    this.pendingEvents = [];
    
    if (process.env.NODE_ENV === 'development') {
      console.log(`[VoteRealtime] ${events.length}к°ңмқҳ лҢҖкё° мӨ‘мқё мқҙлІӨнҠё мІҳлҰ¬`);
    }
    
    events.forEach(event => {
      this.eventListeners.forEach(listener => {
        try {
          listener(event);
        } catch (error) {
          console.error('[VoteRealtime] лҢҖкё° мқҙлІӨнҠё лҰ¬мҠӨл„Ҳ мҳӨлҘҳ:', error);
        }
      });
    });
  }

  /**
   * мҳӨлҘҳ нғҖмһ… к°җм§Җ
   */
  private detectErrorType(status: string, error?: any): ErrorType {
    if (!navigator.onLine) return 'network';
    if (status === 'TIMED_OUT') return 'timeout';
    if (status === 'CHANNEL_ERROR') {
      if (error?.message?.includes('auth')) return 'authentication';
      if (error?.message?.includes('rate')) return 'rate_limit';
      return 'subscription';
    }
    return 'unknown';
  }

  /**
   * мҲҳлҸҷ мһ¬м—°кІ° мӢңлҸ„
   */
  public manualReconnect(): void {
    if (!this.isOnline) {
      console.warn('[VoteRealtime] л„ӨнҠёмӣҢнҒ¬к°Җ мҳӨн”„лқјмқё мғҒнғңмһ…лӢҲлӢӨ.');
      return;
    }
    
    // мһ¬м—°кІ° мӢңлҸ„ нҡҹмҲҳ лҰ¬м…Ӣ
    this.reconnectAttempts = 0;
    this.reconnectAllChannels();
  }

  /**
   * мһ¬м—°кІ° мІҳлҰ¬ (к°ңм„ лҗЁ)
   */
  private handleReconnection(
    channelName: string, 
    voteId: number, 
    type: 'vote' | 'artist' = 'vote',
    errorType?: ErrorType
  ): void {
    // мҳӨн”„лқјмқёмқҙкұ°лӮҳ нҺҳмқҙм§Җк°Җ мҲЁкІЁм§„ мғҒнғңл©ҙ мһ¬м—°кІ°н•ҳм§Җ м•ҠмқҢ
    if (!this.isOnline || !this.isVisible) {
      console.log(`[VoteRealtime] мһ¬м—°кІ° мЎ°кұҙ л¶Ҳм¶©мЎұ: online=${this.isOnline}, visible=${this.isVisible}`);
      return;
    }

    if (this.reconnectAttempts >= this.maxReconnectAttempts) {
      console.error(`[VoteRealtime] мөңлҢҖ мһ¬м—°кІ° мӢңлҸ„ нҡҹмҲҳ мҙҲкіј: ${channelName}`);
      this.updateConnectionStatus('error', {
        type: errorType || 'unknown',
        message: 'мөңлҢҖ мһ¬м—°кІ° мӢңлҸ„ нҡҹмҲҳлҘј мҙҲкіјн–ҲмҠөлӢҲлӢӨ.'
      });
      return;
    }

    // кё°мЎҙ нғҖмқҙлЁёк°Җ мһҲмңјл©ҙ м ңкұ°
    const existingTimeout = this.reconnectTimeouts.get(channelName);
    if (existingTimeout) {
      clearTimeout(existingTimeout);
    }

    this.reconnectAttempts++;
    this.updateConnectionStatus('reconnecting');
    
    // м§ҖмҲҳ л°ұмҳӨн”„ кі„мӮ° (м§Җн„° м¶”к°Җ)
    const baseDelay = this.baseReconnectDelay * Math.pow(2, this.reconnectAttempts - 1);
    const jitter = Math.random() * 1000; // мөңлҢҖ 1мҙҲ м§Җн„°
    const delay = Math.min(baseDelay + jitter, this.maxReconnectDelay);
    
    this.connectionInfo.nextReconnectAt = new Date(Date.now() + delay);

    if (process.env.NODE_ENV === 'development') {
      console.log(`[VoteRealtime] ${Math.round(delay)}ms нӣ„ мһ¬м—°кІ° мӢңлҸ„ (${this.reconnectAttempts}/${this.maxReconnectAttempts}): ${channelName}`);
    }

    const timeout = setTimeout(() => {
      // кё°мЎҙ мұ„л„җ м •лҰ¬
      this.unsubscribeFromChannel(channelName);
      this.reconnectTimeouts.delete(channelName);
      
      // мһ¬м—°кІ° мӢңлҸ„
      if (type === 'artist') {
        this.subscribeToArtistVote(voteId);
      } else {
        this.subscribeToVote(voteId);
      }
    }, delay);

    this.reconnectTimeouts.set(channelName, timeout);
  }

  /**
   * м•„нӢ°мҠӨнҠё нҲ¬н‘ңм—җ лҢҖн•ң мӢӨмӢңк°„ кө¬лҸ… мӢңмһ‘ (к°ңм„ лҗЁ)
   */
  subscribeToArtistVote(artistVoteId: number): void {
    const channelName = `artist_vote_${artistVoteId}`;
    
    if (this.channels.has(channelName)) {
      console.warn(`[VoteRealtime] мқҙлҜё кө¬лҸ… мӨ‘мқё м•„нӢ°мҠӨнҠё нҲ¬н‘ң: ${artistVoteId}`);
      return;
    }

    // мҳӨн”„лқјмқёмқҙкұ°лӮҳ нҺҳмқҙм§Җк°Җ мҲЁкІЁм§„ мғҒнғңл©ҙ кө¬лҸ…н•ҳм§Җ м•ҠмқҢ
    if (!this.isOnline || !this.isVisible) {
      console.warn(`[VoteRealtime] кө¬лҸ… мЎ°кұҙ л¶Ҳм¶©мЎұ: online=${this.isOnline}, visible=${this.isVisible}`);
      return;
    }

    this.updateConnectionStatus('connecting');

    const channel = this.supabase
      .channel(channelName)
      .on(
        'postgres_changes',
        {
          event: 'UPDATE',
          schema: 'public',
          table: 'artist_vote',
          filter: `id=eq.${artistVoteId}`
        },
        (payload: RealtimePostgresChangesPayload<ArtistVoteTable>) => {
          if (payload.new && typeof payload.new === 'object') {
            this.emitEvent({
              type: 'artist_vote_updated',
              payload: payload.new as ArtistVoteTable
            });
          }
        }
      )
      .on(
        'postgres_changes',
        {
          event: 'UPDATE',
          schema: 'public',
          table: 'artist_vote_item',
          filter: `artist_vote_id=eq.${artistVoteId}`
        },
        (payload: RealtimePostgresChangesPayload<ArtistVoteItemTable>) => {
          if (payload.new && typeof payload.new === 'object') {
            this.emitEvent({
              type: 'artist_vote_item_updated',
              payload: payload.new as ArtistVoteItemTable
            });
          }
        }
      )
      .subscribe((status, error) => {
        if (status === 'SUBSCRIBED') {
          this.updateConnectionStatus('connected');
          this.reconnectAttempts = 0;
          this.processPendingEvents(); // лҢҖкё° мӨ‘мқё мқҙлІӨнҠё мІҳлҰ¬
          
          if (process.env.NODE_ENV === 'development') {
            console.log(`[VoteRealtime] м•„нӢ°мҠӨнҠё нҲ¬н‘ң ${artistVoteId} кө¬лҸ… м„ұкіө`);
          }
        } else if (status === 'CHANNEL_ERROR' || status === 'TIMED_OUT') {
          const errorType = this.detectErrorType(status, error);
          const errorMessage = error?.message || `Connection ${status.toLowerCase()}`;
          
          this.updateConnectionStatus('error', {
            type: errorType,
            message: errorMessage
          });
          
          this.handleReconnection(channelName, artistVoteId, 'artist', errorType);
        } else if (status === 'CLOSED') {
          this.updateConnectionStatus('disconnected');
        }
      });

    this.channels.set(channelName, channel);
  }

  /**
   * нҠ№м • нҲ¬н‘ңм—җ лҢҖн•ң мӢӨмӢңк°„ кө¬лҸ… мӢңмһ‘ (к°ңм„ лҗЁ)
   */
  subscribeToVote(voteId: number): void {
    const channelName = `vote_${voteId}`;
    
    if (this.channels.has(channelName)) {
      console.warn(`[VoteRealtime] мқҙлҜё кө¬лҸ… мӨ‘мқё нҲ¬н‘ң: ${voteId}`);
      return;
    }

    // мҳӨн”„лқјмқёмқҙкұ°лӮҳ нҺҳмқҙм§Җк°Җ мҲЁкІЁм§„ мғҒнғңл©ҙ кө¬лҸ…н•ҳм§Җ м•ҠмқҢ
    if (!this.isOnline || !this.isVisible) {
      console.warn(`[VoteRealtime] кө¬лҸ… мЎ°кұҙ л¶Ҳм¶©мЎұ: online=${this.isOnline}, visible=${this.isVisible}`);
      return;
    }

    this.updateConnectionStatus('connecting');

    const channel = this.supabase
      .channel(channelName)
      .on(
        'postgres_changes',
        {
          event: 'UPDATE',
          schema: 'public',
          table: 'vote',
          filter: `id=eq.${voteId}`
        },
        (payload: RealtimePostgresChangesPayload<VoteTable>) => {
          if (payload.new && typeof payload.new === 'object') {
            this.emitEvent({
              type: 'vote_updated',
              payload: payload.new as VoteTable
            });
          }
        }
      )
      .on(
        'postgres_changes',
        {
          event: 'UPDATE',
          schema: 'public',
          table: 'vote_item',
          filter: `vote_id=eq.${voteId}`
        },
        (payload: RealtimePostgresChangesPayload<VoteItemTable>) => {
          if (payload.new && typeof payload.new === 'object') {
            this.emitEvent({
              type: 'vote_item_updated',
              payload: payload.new as VoteItemTable
            });
          }
        }
      )
      .on(
        'postgres_changes',
        {
          event: 'INSERT',
          schema: 'public',
          table: 'vote_pick',
          filter: `vote_id=eq.${voteId}`
        },
        (payload: RealtimePostgresChangesPayload<VotePickTable>) => {
          if (payload.new && typeof payload.new === 'object') {
            this.emitEvent({
              type: 'vote_pick_created',
              payload: payload.new as VotePickTable
            });
          }
        }
      )
      .subscribe((status, error) => {
        if (status === 'SUBSCRIBED') {
          this.updateConnectionStatus('connected');
          this.reconnectAttempts = 0;
          this.processPendingEvents(); // лҢҖкё° мӨ‘мқё мқҙлІӨнҠё мІҳлҰ¬
          
          if (process.env.NODE_ENV === 'development') {
            console.log(`[VoteRealtime] нҲ¬н‘ң ${voteId} кө¬лҸ… м„ұкіө`);
          }
        } else if (status === 'CHANNEL_ERROR' || status === 'TIMED_OUT') {
          const errorType = this.detectErrorType(status, error);
          const errorMessage = error?.message || `Connection ${status.toLowerCase()}`;
          
          this.updateConnectionStatus('error', {
            type: errorType,
            message: errorMessage
          });
          
          this.handleReconnection(channelName, voteId, 'vote', errorType);
        } else if (status === 'CLOSED') {
          this.updateConnectionStatus('disconnected');
        }
      });

    this.channels.set(channelName, channel);
  }

  /**
   * нҠ№м • нҲ¬н‘ң кө¬лҸ… н•ҙм ң
   */
  unsubscribeFromVote(voteId: number): void {
    const channelName = `vote_${voteId}`;
    this.unsubscribeFromChannel(channelName);
    this.dataSyncCallbacks.delete(voteId); // лҚ°мқҙн„° лҸҷкё°нҷ” мҪңл°ұлҸ„ м ңкұ°
  }

  /**
   * нҠ№м • м•„нӢ°мҠӨнҠё нҲ¬н‘ң кө¬лҸ… н•ҙм ң
   */
  unsubscribeFromArtistVote(artistVoteId: number): void {
    const channelName = `artist_vote_${artistVoteId}`;
    this.unsubscribeFromChannel(channelName);
    this.dataSyncCallbacks.delete(artistVoteId); // лҚ°мқҙн„° лҸҷкё°нҷ” мҪңл°ұлҸ„ м ңкұ°
  }

  /**
   * мұ„л„җ кө¬лҸ… н•ҙм ң (к°ңм„ лҗЁ)
   */
  private unsubscribeFromChannel(channelName: string): void {
    const channel = this.channels.get(channelName);
    if (channel) {
      this.supabase.removeChannel(channel);
      this.channels.delete(channelName);
      
      // мһ¬м—°кІ° нғҖмқҙлЁёк°Җ мһҲмңјл©ҙ м ңкұ°
      const timeout = this.reconnectTimeouts.get(channelName);
      if (timeout) {
        clearTimeout(timeout);
        this.reconnectTimeouts.delete(channelName);
      }
      
      if (process.env.NODE_ENV === 'development') {
        console.log(`[VoteRealtime] мұ„л„җ кө¬лҸ… н•ҙм ң: ${channelName}`);
      }
    }
  }

  /**
   * лӘЁл“  кө¬лҸ… н•ҙм ң л°Ҹ м •лҰ¬ (к°ңм„ лҗЁ)
   */
  unsubscribeAll(): void {
    // лӘЁл“  мұ„л„җ кө¬лҸ… н•ҙм ң
    this.channels.forEach((channel, channelName) => {
      this.supabase.removeChannel(channel);
      
      if (process.env.NODE_ENV === 'development') {
        console.log(`[VoteRealtime] мұ„л„җ кө¬лҸ… н•ҙм ң: ${channelName}`);
      }
    });
    
    // лӘЁл“  нғҖмқҙлЁё м ңкұ°
    this.reconnectTimeouts.forEach(timeout => clearTimeout(timeout));
    this.reconnectTimeouts.clear();
    
    // н•ҳнҠёл№„нҠё мӨ‘м§Җ
    if (this.heartbeatInterval) {
      clearInterval(this.heartbeatInterval);
      this.heartbeatInterval = null;
    }
    
    // мқҙлІӨнҠё лҰ¬мҠӨл„Ҳ м ңкұ°
    if (typeof window !== 'undefined') {
      window.removeEventListener('online', this.handleOnline.bind(this));
      window.removeEventListener('offline', this.handleOffline.bind(this));
    }
    if (typeof document !== 'undefined') {
      document.removeEventListener('visibilitychange', this.handleVisibilityChange.bind(this));
    }
    
    // мғҒнғң мҙҲкё°нҷ”
    this.channels.clear();
    this.eventListeners.clear();
    this.statusListeners.clear();
    this.dataSyncCallbacks.clear();
    this.pendingEvents = [];
    this.updateConnectionStatus('disconnected');
    this.reconnectAttempts = 0;
  }

  /**
   * м—°кІ° мғҒнғң нҷ•мқё
   */
  isConnected(): boolean {
    return this.connectionStatus === 'connected';
  }

  /**
   * нҷңм„ұ кө¬лҸ… мҲҳ л°ҳнҷҳ
   */
  getActiveSubscriptionsCount(): number {
    return this.channels.size;
  }

  /**
   * нҷңм„ұ кө¬лҸ… лӘ©лЎқ л°ҳнҷҳ
   */
  getActiveSubscriptions(): string[] {
    return Array.from(this.channels.keys());
  }

  /**
   * лҢҖкё° мӨ‘мқё мқҙлІӨнҠё мҲҳ л°ҳнҷҳ
   */
  getPendingEventsCount(): number {
    return this.pendingEvents.length;
  }

  /**
   * м—°кІ° нҶөкі„ л°ҳнҷҳ
   */
  getConnectionStats() {
    return {
      status: this.connectionStatus,
      isOnline: this.isOnline,
      isVisible: this.isVisible,
      reconnectAttempts: this.reconnectAttempts,
      maxReconnectAttempts: this.maxReconnectAttempts,
      activeSubscriptions: this.getActiveSubscriptionsCount(),
      pendingEvents: this.getPendingEventsCount(),
      lastHeartbeat: this.lastHeartbeat,
      connectionInfo: this.getConnectionInfo()
    };
  }
}

// мӢұкёҖнҶӨ мқёмҠӨн„ҙмҠӨ
let voteRealtimeService: VoteRealtimeService | null = null;

/**
 * нҲ¬н‘ң Realtime м„ңл№„мҠӨ мӢұкёҖнҶӨ мқёмҠӨн„ҙмҠӨ л°ҳнҷҳ
 */
export function getVoteRealtimeService(): VoteRealtimeService {
  if (!voteRealtimeService) {
    voteRealtimeService = new VoteRealtimeService();
  }
  return voteRealtimeService;
}

/**
 * м»ҙнҸ¬л„ҢнҠё м–ёл§ҲмҡҙнҠё мӢң м •лҰ¬ н•ЁмҲҳ
 */
export function cleanupVoteRealtime(): void {
  if (voteRealtimeService) {
    voteRealtimeService.unsubscribeAll();
    voteRealtimeService = null;
  }
} 